const AWS = require('aws-sdk');
const child_process = require('child_process');

exports.handler = async (event) => {
  const s3 = new AWS.S3();
  const bucketName = event.Records[0].s3.bucket.name;
  const imageKey = event.Records[0].s3.object.key;
  const outputFormat = event.Records[0].s3.outputFormat;

  // Execute ImageMagick convert command with parameters from the event
  child_process.exec(`convert ${imageKey} -format ${outputFormat} ${bucketName}/${imageKey}.${outputFormat}`);
};